VALUES
  ('social-worker-moex-07730', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作認為如何開創和增進團體動力對團體工作進行是很重要的，下列何者對於團體動力相關概念的 描述為真？', '["好的團體工作者不應會讓團體裡產生次團體", "成員座位安排不會影響團體對成員的吸引力", "團體中的團體規範較成員角色期待容易改變", "好的團體動力能夠滿足團體成員情緒的需求"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "14a4dbfc792f", "answer_pdf_sha1": "97d8d75691dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07731', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體工作進行過程中會產生一些治療性因素，下列何者對治療因素的陳述為真？', '["「替代學習」治療性因素是指「協助成員了解並克服自己內在抗拒與誤解的重要性」", "「植入希望」治療性因素是指「成員經由團體中的親身經驗，對自己的改變抱持樂觀看法」", "「社交行為中學習」治療性因素是指「讓成員感覺在團體中不被排斥且受重視的感受」", "「利他主義」治療性因素是指「在團體中不論是過去或此時此刻的情緒能夠獲得紓解」"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "14a4dbfc792f", "answer_pdf_sha1": "97d8d75691dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07732', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在自願性的團體裡，團體工作者與成員之間的互動情況會因為不同的團體發展階段而有不同，下列陳述 何者為真？', '["團體初期，成員因為畏懼團體工作者，反而會花時間和其他成員互動", "團體中期，成員熟悉團體運作以後，會開始挑戰團體工作者的領導權", "團體末期，成員們對工作者因團體即將結束而產生莫名奇妙的罪惡感", "其實不論團體工作者在機構的地位如何，都不會影響他和成員的關係"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "14a4dbfc792f", "answer_pdf_sha1": "97d8d75691dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07733', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列對「心理暨社會學派」的陳述何者為真？', '["又可稱之為功能派社會工作", "其理論依據是來自系統理論", "短時間之內就可以解決問題", "強調「人在情境中」的概念"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "14a4dbfc792f", "answer_pdf_sha1": "97d8d75691dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07734', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者對於保密的陳述為真？', '["與案主利益相衝突時，社會工作者對案主的保密會受到限制", "為了讓案主確認自己的選擇和決定如何處理問題所做的措施", "能客觀考量，避免對案主行為原因和處境產生偏見的倫理要求", "是回應案主希望其行為不被批評和指責對錯的一種具體作法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "14a4dbfc792f", "answer_pdf_sha1": "97d8d75691dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07735', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者對於案主自我決定的陳述為真？', '["是為了滿足案主對其問題希望獲得對方反應和瞭解的需求", "在「案主有能力作積極建設決定」的假設前提下才能成立", "是考量案主不希望別人知道他的隱私或秘密而定的倫理要求", "從案主的觀點和處境來暸解和澄清問題，就是最具體的作法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "14a4dbfc792f", "answer_pdf_sha1": "97d8d75691dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07736', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者對於社會個案工作專業關係的陳述為真？', '["只有與對方有相同經驗，才能和他建立好關係", "當案主需要的是物質的資助時，關係並不重要", "太過關心和關懷的關係，會造成案主的依賴", "當社會工作者確認接案後，專業關係才開始"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "14a4dbfc792f", "answer_pdf_sha1": "97d8d75691dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07737', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於情感轉移產生原因的陳述，下列何者為真？', '["是受到我國特有的權威性格、人情關係、「以和為貴」等文化價值影響而產生的", "是起因於種族或社會階層中，對對方文化的態度，所造成互相不瞭解的一種偏見", "是來自於對人與現實生活、對案主與其問題、人性弱點等，一種自然的態度反應", "是把對生活、人際關係的感覺、想法、情緒、幻想等表現在對方身上的情緒反應"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "14a4dbfc792f", "answer_pdf_sha1": "97d8d75691dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07738', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '相較於自願性案主，非自願性案主比較常出現那些行為來影響社會工作者對案主的接納和尊重？①不配', '["攻擊和悶悶不樂", "開朗樂觀", "沉默或退縮  ⑤主動積極  ⑥戒慎恐懼", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "14a4dbfc792f", "answer_pdf_sha1": "97d8d75691dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07739', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列那一個組合是屬於任務性團體？①大樓管理委員會  ②聯合工會  ③病友支持團體  ④父母效能訓 練團體  ⑤董事會', '["", "", "⑤", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "14a4dbfc792f", "answer_pdf_sha1": "97d8d75691dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
